static Mat subMat2(const Mat& a, const Mat& b, int sz) {
    Mat r = makeMat(sz);
    for (int i = 0; i < sz; i++)
        for (int j = 0; j < sz; j++)
            r[i][j] = a[i][j] - b[i][j];
